// ═══════════════════════════════════════════════════════════════
// TEMPLATE SANITIZADO — db_registrar_pago v1
// ═══════════════════════════════════════════════════════════════
// Este JSON es un template genérico para importar en n8n.
// No contiene credenciales, IDs de Sheet ni IDs de workflow reales.
//
// Antes de importar, reemplazar:
//   __SHEETS_ID__                              → ID del Google Sheet del entorno
//   __CREDENTIAL_ID__                          → ID de la credencial OAuth en n8n
//   __CREDENTIAL_NAME__                        → Nombre de la credencial OAuth en n8n
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__  → ID de db_recalcular_disponibilidad
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_NAME__ → Nombre de db_recalcular_disponibilidad
//
// El mismo template sirve para DEV, TEST y PROD.
// Solo cambia __SHEETS_ID__ y las credenciales.
// ═══════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// NODO 1 — Resolver Input
// ═══════════════════════════════════════════════════════════════
// ALCANCE v1:
// ✅ Registra un pago reportado manualmente por el huésped.
// ✅ Crea fila en PAGOS con estado = en_revision.
// ✅ Actualiza PRE_RESERVAS: estado → pago_en_revision,
//    intentos_pago +1, referencia_mp, updated_at.
// ✅ Escribe LOG_CAMBIOS.
// ✅ Recalcula DISPONIBILIDAD_CACHE al final.
//
// ❌ FUERA DE ALCANCE en v1:
//    - MercadoPago automático
//    - Confirmación de reserva definitiva
//    - Creación de RESERVA
//    - WhatsApp / notificaciones
//    - IA
//    - Bypass de pago duplicado
//
// ⚠️  SHEETS_ID — __ENTORNO__
// Valor actual: __SHEETS_ID__
//
// ⚠️  WORKFLOW ID — db_recalcular_disponibilidad
// El nodo 'Ejecutar Recalculo Final' apunta a:
// __RECALCULAR_DISPONIBILIDAD_WORKFLOW_NAME__ → ID: __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__
//
// ⚠️  id_pago usa max + 1. Race condition posible en alta
// concurrencia. Para producción con carga alta, migrar a UUID.
// ═══════════════════════════════════════════════════════════════

const SHEETS_ID = '__SHEETS_ID__'; // __ENTORNO__

const METODOS_PAGO_VALIDOS = ['mp_link', 'transferencia_mp', 'transferencia_bancaria', 'tarjeta', 'efectivo', 'cripto'];

// ── MANUAL_INPUT ──────────────────────────────────────────────
// Editar estos valores para pruebas manuales del entorno correspondiente.
// Se usan SOLO si el Manual Trigger viene vacío.
const MANUAL_INPUT = {
  id_prereserva:        1,
  monto_reportado:      50000,
  metodo_pago:          'transferencia_mp',
  referencia_pago:      'TEST-TRANSFERENCIA-001',
  comprobante_url:      'https://example.com/comprobante-test.jpg',
  fecha_pago_reportada: '',
  notas:                'Pago de prueba',
  source_event:         'manual'  // editar según entorno
};
// ─────────────────────────────────────────────────────────────

const raw             = $input.first()?.json ?? {};
const usandoManualInput = !raw.id_prereserva && !raw.monto_reportado;
const input           = usandoManualInput ? MANUAL_INPUT : raw;

const id_prereserva       = parseInt(String(input.id_prereserva ?? ''), 10);
const monto_reportado     = parseFloat(String(input.monto_reportado ?? ''));
const metodo_pago         = String(input.metodo_pago        ?? '').trim();
const referencia_pago     = String(input.referencia_pago    ?? '').trim();
const comprobante_url     = String(input.comprobante_url    ?? '').trim();
const fecha_pago_str      = String(input.fecha_pago_reportada ?? '').trim();
const notas               = String(input.notas              ?? '').trim();
const source_event        = String(input.source_event       ?? 'manual').trim();

// Si fecha_pago_reportada viene vacía o no viene, usar now
const fecha_pago_reportada = (fecha_pago_str && fecha_pago_str !== '')
  ? fecha_pago_str
  : new Date().toISOString();

// ── Validaciones ─────────────────────────────────────────────
const errores = [];

if (isNaN(id_prereserva) || id_prereserva <= 0)
  errores.push('id_prereserva es obligatorio y debe ser entero positivo');
if (isNaN(monto_reportado) || monto_reportado <= 0)
  errores.push('monto_reportado debe ser mayor a 0');
if (!METODOS_PAGO_VALIDOS.includes(metodo_pago))
  errores.push(`metodo_pago inválido: '${metodo_pago}'. Válidos: ${METODOS_PAGO_VALIDOS.join(', ')}`);

if (errores.length > 0) {
  return [{ json: { ok: false, error: 'input_invalido', detalle: errores, _validado: false } }];
}

return [{ json: {
  SHEETS_ID,
  id_prereserva,
  monto_reportado,
  metodo_pago,
  referencia_pago,
  comprobante_url,
  fecha_pago_reportada,
  notas,
  source_event,
  ts_inicio: new Date().toISOString(),
  _validado: true,
  _usando_manual_input: usandoManualInput
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 2 — Verificar PRE_RESERVA
// ═══════════════════════════════════════════════════════════════
// Validaciones en orden:
//   1. PRE_RESERVA existe
//   2. estado = pendiente_pago
//   3. no está vencida (expira_en > now)
//   4. no hay pago duplicado (PAGOS con mismo id_prereserva
//      y estado IN ('en_revision', 'confirmado'))
//
// Si todo OK:
//   - extrae monto_sena como monto_esperado
//   - calcula id_pago = max + 1
//   - devuelve _verificacion_ok: true
// ═══════════════════════════════════════════════════════════════

const inputData = $('Resolver Input').first().json;
const ahora     = new Date();

function parseTimestamp(val) {
  if (!val && val !== 0) return null;
  if (val instanceof Date) return isNaN(val.getTime()) ? null : val;
  if (typeof val === 'number') {
    const d = val < 200000
      ? new Date(Date.UTC(1899, 11, 30) + val * 86400000)
      : new Date(val);
    return isNaN(d.getTime()) ? null : d;
  }
  const s = String(val).trim();
  if (!s) return null;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
}

// Normalizar arrays de Sheets
const prereservas = ($('Agg PRE_RESERVAS').first()?.json?.data ?? [])
  .filter(r => r && Object.keys(r).some(k => String(r[k]).trim() !== ''));
const pagos       = ($('Agg PAGOS').first()?.json?.data ?? [])
  .filter(r => r && Object.keys(r).some(k => String(r[k]).trim() !== ''));

// 1. Buscar PRE_RESERVA
const prereserva = prereservas.find(
  p => parseInt(String(p.id_prereserva), 10) === inputData.id_prereserva
);

if (!prereserva) {
  return [{ json: {
    ok: false, error: 'prereserva_no_encontrada',
    detalle: [`id_prereserva ${inputData.id_prereserva} no existe en PRE_RESERVAS`],
    _verificacion_ok: false
  }}];
}

// 2. Verificar estado
const estadoPR = String(prereserva.estado ?? '').trim();
if (estadoPR !== 'pendiente_pago') {
  return [{ json: {
    ok: false, error: 'prereserva_estado_invalido',
    detalle: [`PRE_RESERVA ${inputData.id_prereserva} tiene estado '${estadoPR}'. Se requiere 'pendiente_pago'.`],
    estado_actual: estadoPR,
    _verificacion_ok: false
  }}];
}

// 3. Verificar vencimiento
const expiraTs = parseTimestamp(prereserva.expira_en);
if (!expiraTs || expiraTs <= ahora) {
  return [{ json: {
    ok: false, error: 'prereserva_vencida',
    detalle: [`PRE_RESERVA ${inputData.id_prereserva} está vencida. expira_en: ${prereserva.expira_en}`],
    expira_en: prereserva.expira_en,
    _verificacion_ok: false
  }}];
}

// 4. Detectar pago duplicado
// Estados bloqueantes: en_revision (esperando revisión) o confirmado (ya procesado)
const ESTADOS_DUPLICADO = ['en_revision', 'confirmado'];
const pagoDuplicado = pagos.find(p =>
  parseInt(String(p.id_prereserva), 10) === inputData.id_prereserva &&
  ESTADOS_DUPLICADO.includes(String(p.estado ?? '').trim())
);

if (pagoDuplicado) {
  return [{ json: {
    ok: false, error: 'pago_duplicado_posible',
    detalle: [`Ya existe un pago para id_prereserva ${inputData.id_prereserva} con estado '${pagoDuplicado.estado}'.`],
    pago_existente: {
      id_pago:   pagoDuplicado.id_pago,
      estado:    pagoDuplicado.estado,
      medio_pago: pagoDuplicado.medio_pago,
      created_at: pagoDuplicado.created_at
    },
    _verificacion_ok: false
  }}];
}

// 5. Calcular id_pago = max + 1
const ids_pago = pagos
  .map(p => parseInt(String(p.id_pago ?? ''), 10))
  .filter(n => !isNaN(n) && n > 0);
const nuevo_id_pago = (ids_pago.length > 0 ? Math.max(...ids_pago) : 0) + 1;

// 6. Extraer monto_esperado de la pre-reserva
const monto_esperado = parseFloat(String(prereserva.monto_sena ?? '0')) || 0;
const intentos_pago_actual = parseInt(String(prereserva.intentos_pago ?? '0'), 10) || 0;

return [{ json: {
  _verificacion_ok: true,
  inputData,
  prereserva,
  nuevo_id_pago,
  monto_esperado,
  intentos_pago_actual
}}];

// Retornar error controlado — sin escribir nada en Sheets
const d = $input.first().json;
return [{ json: {
  ok:     d.ok,
  error:  d.error,
  detalle: d.detalle,
  ...(d.estado_actual    ? { estado_actual: d.estado_actual }       : {}),
  ...(d.expira_en        ? { expira_en: d.expira_en }               : {}),
  ...(d.pago_existente   ? { pago_existente: d.pago_existente }     : {})
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 3 — Preparar Fila PAGOS
// ═══════════════════════════════════════════════════════════════
// Construye la fila completa de 22 columnas para PAGOS.
//
// Mapeo:
//   tipo        = 'sena' (default v1)
//   medio_pago  = input.metodo_pago
//   monto_esperado = PRE_RESERVAS.monto_sena
//   monto_recibido = input.monto_reportado
//   moneda      = 'ARS' (default v1)
//   estado      = 'en_revision'
//   es_automatico = FALSE (siempre manual en v1)
//   referencia_externa = input.referencia_pago
//   Campos vacíos en v1: id_reserva, proveedor, cuenta_destino,
//     tx_hash, validado_por, validado_en, motivo_rechazo
// ═══════════════════════════════════════════════════════════════

const d     = $input.first().json;
const { inputData, nuevo_id_pago, monto_esperado } = d;
const ahora = new Date().toISOString();

return [{ json: {
  // ── Datos para Escribir PAGOS ────────────────────────────
  fila_pagos: {
    id_pago:            nuevo_id_pago,
    id_prereserva:      inputData.id_prereserva,
    id_reserva:         '',
    tipo:               'sena',
    medio_pago:         inputData.metodo_pago,
    proveedor:          '',
    cuenta_destino:     '',
    monto_esperado:     monto_esperado,
    monto_recibido:     inputData.monto_reportado,
    moneda:             'ARS',
    estado:             'en_revision',
    es_automatico:      false,
    comprobante_url:    inputData.comprobante_url,
    referencia_externa: inputData.referencia_pago,
    tx_hash:            '',
    validado_por:       '',
    validado_en:        '',
    motivo_rechazo:     '',
    notas:              inputData.notas,
    source_event:       inputData.source_event,
    created_at:         ahora,
    updated_at:         ahora
  },
  // ── Datos para Actualizar PRE_RESERVAS ───────────────────
  update_prereserva: {
    id_prereserva:  inputData.id_prereserva,
    estado:         'pago_en_revision',
    intentos_pago:  d.intentos_pago_actual + 1,
    referencia_mp:  inputData.referencia_pago,
    updated_at:     ahora
  },
  // ── Metadata para LOG y Resumen ──────────────────────────
  nuevo_id_pago,
  monto_esperado,
  inputData
}}];

// Preparar los campos a actualizar en PRE_RESERVAS
const d = $('Preparar Fila PAGOS').first().json;
return [{ json: d.update_prereserva }];

// ═══════════════════════════════════════════════════════════════
// NODO 4 — Preparar LOG_CAMBIOS
// ═══════════════════════════════════════════════════════════════
const d     = $('Preparar Fila PAGOS').first().json;
const ahora = new Date();

return [{ json: {
  id_log:           `LOG-PAGO-${ahora.getTime()}`,
  fecha_hora:        ahora.toISOString(),
  tabla_afectada:   'PRE_RESERVAS',
  id_registro:      String(d.inputData.id_prereserva),
  campo_modificado: 'estado',
  valor_anterior:   'pendiente_pago',
  valor_nuevo:      'pago_en_revision',
  modificado_por:   'n8n',
  source_event:     d.inputData.source_event,
  nivel:            'info',
  detalle: JSON.stringify({
    id_pago:                d.nuevo_id_pago,
    id_prereserva:          d.inputData.id_prereserva,
    medio_pago:             d.inputData.metodo_pago,
    monto_recibido:         d.inputData.monto_reportado,
    monto_esperado:         d.monto_esperado,
    referencia_externa:     d.inputData.referencia_pago,
    requiere_revision_manual: true
  })
}}];

// Preparar llamada a db_recalcular_disponibilidad
// Recálculo completo — sin scope parcial.
// source_event identifica que el trigger fue un pago reportado.
return [{ json: { source_event: 'pago_reportado' } }];

// ═══════════════════════════════════════════════════════════════
// NODO FINAL — Resumen
// ═══════════════════════════════════════════════════════════════
// continueOnFail = true en Ejecutar Recalculo Final garantiza
// que este nodo siempre se ejecuta.
//
// Si el recálculo falló:
//   - El pago ya fue registrado en PAGOS.
//   - PRE_RESERVAS ya fue actualizada a pago_en_revision.
//   - LOG_CAMBIOS ya fue escrito.
//   - Solo la cache puede estar desactualizada.
//   - Acción: ejecutar db_recalcular_disponibilidad manualmente.
// ═══════════════════════════════════════════════════════════════

const d = $('Preparar Fila PAGOS').first().json;

// Detectar si el recálculo falló
const recalculoOutput = $('Ejecutar Recalculo Final').first()?.json ?? {};
const recalculo_fallo = !!recalculoOutput.error || recalculoOutput.ok === false;

return [{ json: {
  ok:                       true,
  id_pago:                  d.nuevo_id_pago,
  id_prereserva:            d.inputData.id_prereserva,
  estado_pago:              'en_revision',
  estado_prereserva:        'pago_en_revision',
  requiere_revision_manual: true,
  recalculo_cache:          recalculo_fallo ? 'warning' : 'ok',
  recalculo_error:          recalculo_fallo
    ? 'db_recalcular_disponibilidad falló después de registrar el pago. Cache puede estar desactualizada. Ejecutar recálculo manual.'
    : null,
  mensaje: 'Pago registrado para revisión manual'
}}];
